#!/usr/bin/env node
/**
 * setup.mjs — LexVault project materialiser.
 * Recreates every file/directory of the LexVault skeleton, byte-for-byte.
 * Cross-platform: works in PowerShell, cmd, or bash. Just:  node setup.mjs
 *
 * Safe: it only WRITES the project files. It will refuse to overwrite an
 * existing src/ unless you pass --force, so you cannot clobber your work.
 */
